using System.Text;
using System.Linq;
using Roscoff.Application.Dtos.Catalog;

namespace Roscoff.Infrastructure.Pdf;

public static class MenuTemplateGenerator
{
    public static string GenerateHtml(MenuResponseDto menu)
    {
        var sb = new StringBuilder();
        
        // Inserisci qui il percorso, l'URL o la stringa Base64 del tuo logo
        string logoSrc = "data:image/jpg;base64,"; 

        // Raggruppiamo i piatti per categoria usando il DTO aggiornato
        var groupedItems = menu.MenuItems
            .GroupBy(mi => mi.CategoryName ?? "Varie")
            .ToList();

        sb.Append($@"
        <!DOCTYPE html>
        <html lang='it'>
        <head>
            <meta charset='UTF-8'>
            <style>
                @import url('https://fonts.cdnfonts.com/css/futura-std');
                @page {{ size: A4; margin: 20mm 15mm; }}
                :root {{
                    --brand-black: #000000;
                    --brand-gold: #D4A20A;
                    --brand-gray: #BFBFBF;
                    --brand-light: #f8f9fa;
                }}
                body {{ 
                    font-family: 'Futura Std', 'Futura', sans-serif; 
                    color: var(--brand-black); margin: 0; padding: 0; font-size: 13px; 
                }}
                .menu-header {{ text-align: center; margin-bottom: 40px; border-bottom: 2px solid var(--brand-gold); padding-bottom: 20px; }}
                .logo {{ max-width: 140px; height: auto; margin-bottom: 15px; }}
                .menu-title {{ font-size: 28px; font-weight: bold; text-transform: uppercase; letter-spacing: 2px; margin: 0; }}
                .menu-desc {{ font-size: 14px; color: #555; font-style: italic; margin-top: 5px; }}
                
                .category-section {{ margin-bottom: 35px; page-break-inside: avoid; }}
                .category-title {{ 
                    font-size: 18px; font-weight: bold; color: var(--brand-gold); 
                    text-transform: uppercase; letter-spacing: 1px;
                    border-bottom: 1px solid var(--brand-gray); padding-bottom: 5px; margin-bottom: 20px;
                }}
                .menu-item {{ margin-bottom: 18px; }}
                .item-main {{ display: flex; justify-content: space-between; align-items: baseline; }}
                .item-name {{ font-weight: bold; font-size: 14px; text-transform: uppercase; }}
                .item-dots {{ flex-grow: 1; border-bottom: 1px dotted var(--brand-gray); margin: 0 10px; }}
                .item-price {{ font-weight: bold; font-size: 14px; white-space: nowrap; }}
                .item-description {{ font-size: 11px; color: #666; margin-top: 4px; padding-right: 15%; }}
                
                .footer {{ 
                    position: fixed; bottom: 0; left: 0; right: 0; text-align: center; 
                    font-size: 9px; color: #777; border-top: 1px solid var(--brand-gray); padding-top: 10px;
                }}
            </style>
        </head>
        <body>
            <div class='menu-header'>
                <img src='{logoSrc}' class='logo' alt='Logo' />
                <div class='menu-title'>{menu.Name}</div>
                {(string.IsNullOrEmpty(menu.Description) ? "" : $"<div class='menu-desc'>{menu.Description}</div>")}
            </div>
            <div class='menu-content'>");

        foreach (var categoryGroup in groupedItems)
        {
            sb.Append($@"
                <div class='category-section'>
                    <div class='category-title'>{categoryGroup.Key}</div>");

            foreach (var menuItem in categoryGroup)
            {
                // Gestione del prezzo (Override o BasePrice in centesimi)
                int priceInCents = menuItem.OverridePrice ?? menuItem.BasePrice;
                var formattedPrice = (priceInCents / 100m).ToString("0.00");

                sb.Append($@"
                    <div class='menu-item'>
                        <div class='item-main'>
                            <span class='item-name'>{menuItem.PlateName}</span>
                            <div class='item-dots'></div>
                            <span class='item-price'>€ {formattedPrice}</span>
                        </div>
                        {(menuItem.PlateWeight > 0 ? $"<div class='item-description'>Grammatura: {menuItem.PlateWeight}g</div>" : "")}
                    </div>");
            }
            sb.Append("</div>");
        }

        sb.Append(@"
            </div>
            <div class='footer'>
                <strong>ROSCOFF MEAL SRL</strong> | Via Messina, 101 - 20831 Seregno (MB) | P.IVA / C.F. 03621440638<br>
                info@roscoffmeal.com | www.roscoffmeal.com
            </div>
        </body>
        </html>");

        return sb.ToString();
    }
}